	_, err := o.Raw(sql, params...).QueryRows(&summaries)
	if err!= nil {
		return nil, err
	}
	return summaries, nil
}
// GenerateDepartmentReport creates a summary report grouped by a specified field.
// Parameters:
// - o: the ORM instance
// - departments: list of department names to include (filter by department IN (.))
// - groupByField: which field to group by, must be one of: "department", "role", "display_name"
//
// Returns a slice of maps with keys: "group_value" (the grouped field value), "user_count", "total_activities"
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}
	// Validate group by field to prevent SQL injection
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if!allowedFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %q, must be one of department, role, display_name", groupByField)
	}
	// Create placeholders for department IN clause
	placeholders := make([]string, len(departments))
	for i := range departments {
		placeholders[i] = "?"
	}
	inClause := strings.Join(placeholders, ",")
	// Build SQL with left join to include users with no activities
	sql := fmt.Sprintf(`
		SELECT u.%s AS group_value, COUNT(DISTINCT u.id) AS user_count, COUNT(a.id) AS total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s
	`, groupByField, inClause, groupByField)
	// Build parameters
	params := make([]interface{}, len(departments))
	for i, dept := range departments {
		params[i] = dept
	}
	// Execute query and get results as parameter maps
	var results []orm.Params
	_, err := o.Raw(sql, params...).Values(&results)
	if err!= nil {
		return nil, err
	}
	// Convert []orm.Params to []map[string]interface{}
	reports := make([]map[string]interface{}, len(results))
	for i, res := range results {
		reports[i] = map[string]interface{}(res)
	}
	return reports, nil
}

