	AVG(a.duration_ms) AS avg_duration
FROM user_activity a
INNER JOIN user_profile u ON a.user_id = u.id
WHERE u.username IN (` + strings.Join(usernamePlaceholders, ", ") + `)
AND a.created_at BETWEEN ? AND ?
`

	// Add date parameters
