	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	_, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build IN clause placeholders for usernames
	placeholders := make([]string, len(usernames))
	for i := range placeholders {
		placeholders[i] = "?"
	}
	inClause := strings.Join(placeholders, ", ")

	// Build WHERE clause parts and arguments
	whereParts := []string{
		fmt.Sprintf("u.username IN (%s)", inClause),
		"a.created_at BETWEEN ? AND ?",
	}
	args := make([]interface{}, 0, len(usernames)+2+1) // usernames + 2 dates + optional action type
	for _, un := range usernames {
		args = append(args, un)
	}
	args = append(args, startDate, endDate)

	// Add action type filter if provided
	if actionTypeFilter != "" {
		whereParts = append(whereParts, "a.action_type = ?")
		args = append(args, actionTypeFilter)
	}

	whereClause := strings.Join(whereParts, " AND ")

	sql := fmt.Sprintf(`
SELECT u.display_name, a.action_type, COUNT(*) as total_actions, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, AVG(a.duration_ms) as avg_duration
FROM user_activity a
INNER JOIN user_profile u ON a.user_id = u.id
WHERE %s
GROUP BY u.display_name, a.action_type
	`, whereClause)

	var summaries []UserActivitySummary
	_, err := o.Raw(sql, args...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate allowed group by fields
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %q, must be one of: department, role, display_name", groupByField)
	}

	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Build IN clause placeholders for departments
	placeholders := make([]string, len(departments))
	for i := range placeholders {
		placeholders[i] = "?"
	}
	inClause := strings.Join(placeholders, ", ")

	sql := fmt.Sprintf(`
SELECT u.%s as group_value, COUNT(DISTINCT u.id) as user_count, COUNT(a.id) as total_activities
FROM user_profile u
LEFT JOIN user_activity a ON u.id = a.user_id
WHERE u.department IN (%s)
GROUP BY u.%s
	`, groupByField, inClause, groupByField)

	// Convert departments to interface slice for args
	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		args[i] = dept
	}

	var results []orm.Params
	_, err := o.Raw(sql, args...).Values(&results)
	if err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{} for return type
	report := make([]map[string]interface{}, len(results))
	for i, row := range results {
		report[i] = row
	}

	return report, nil
}

